"use strict";exports.id=4406,exports.ids=[4406],exports.modules={14406:(e,t,n)=>{n.r(t),n.d(t,{javascriptNotes:()=>a});let a=[{id:"js-scoping",title:"Chapter 1: Scoping - Var, Let, and Const",content:"JavaScript has evolved its variable scoping mechanisms. Under ES5, variables declared with `var` are function-scoped or globally-scoped. Under ES6, `let` and `const` introduce block-scoping. Block scope means variables are restricted to the containing braces `{}`.",codeSnippet:{code:`function scopeExample() {
  if (true) {
    var functionScoped = "I'm available throughout the function";
    let blockScoped = "I'm only available inside this block";
    const constantBlock = "I'm also block-scoped and cannot be reassigned";
  }
  console.log(functionScoped); // Prints fine
  // console.log(blockScoped); // ReferenceError!
}`,language:"javascript"},summary:"Prefer const by default for variables that do not need to be reassigned. Use let for variables that change, and avoid var to prevent hoisting bugs.",subtopicChecklist:["Understanding var function scoping & global scope leakage","Understanding let & const block scoping boundaries","Variable hoisting differences between var and let/const","Handling the Temporal Dead Zone (TDZ) in ES6+"],quizQuestions:[{id:"js-scope-q1",question:"Which of the following describes block scope?",options:["Variables declared inside a block can be accessed anywhere in the function","Variables are only accessible inside the enclosing curly braces {}","Variables are hoisted to the top of the file automatically","Variables can be reassigned globally across modules"],correctIndex:1,explanation:"let and const variables are block-scoped, meaning they are bound strictly within the curly braces {} in which they are declared."},{id:"js-scope-q2",question:"What happens when a variable declared with var is hoisted?",options:["It throws a ReferenceError if accessed before declaration","It is moved to the top of its scope and initialized as undefined","It becomes a constant variable automatically","It stays inside the block scope block"],correctIndex:1,explanation:"var declarations are hoisted to the top of their enclosing function or global scope and initialized as undefined. Accessing them before declaration returns undefined rather than throwing an error."},{id:"js-scope-q3",question:"What is the Temporal Dead Zone (TDZ) in JavaScript?",options:["A state when the browser hangs due to infinite loops","The period between entering a block scope and the actual let/const declaration line","The time it takes for a garbage collector to reclaim unused variables","The asynchronous delay inside setTimeout functions"],correctIndex:1,explanation:"The TDZ is the period of time from entering a block scope until the variable is declared via let/const. Any attempts to access the variable within this zone results in a ReferenceError."}]},{id:"js-arrays",title:"Chapter 2: ES6 Array Methods (Map, Filter, Reduce)",content:"ES6 introduced elegant functional methods for array manipulations. They do not mutate the original array but return new elements or calculations.",codeSnippet:{code:`const numbers = [1, 2, 3, 4, 5];

// 1. Map: transform elements
const doubled = numbers.map(num => num * 2); // [2, 4, 6, 8, 10]

// 2. Filter: remove elements
const evens = numbers.filter(num => num % 2 === 0); // [2, 4]

// 3. Reduce: accumulate elements
const sum = numbers.reduce((accumulator, current) => accumulator + current, 0); // 15`,language:"javascript"},summary:"Map maps inputs to outputs 1-to-1, filter subsets inputs based on conditions, and reduce aggregates inputs to a single output value.",subtopicChecklist:["Using map() to transform array elements without mutation","Using filter() to extract matching elements based on conditions","Using reduce() to aggregate values into single objects or primitives","Understanding pure functions and array immutability rules"],quizQuestions:[{id:"js-array-q1",question:"Which array method would you use to transform every element in an array and return a new array of the same length?",options:["Array.prototype.filter()","Array.prototype.map()","Array.prototype.reduce()","Array.prototype.forEach()"],correctIndex:1,explanation:"map() is used to transform every element of an array, yielding a new array of identical length."},{id:"js-array-q2",question:"What does filter() do if no elements match the condition?",options:["Returns undefined","Returns an empty array []","Throws a TypeError","Returns null"],correctIndex:1,explanation:"If no elements pass the conditional check, filter() returns an empty array []."},{id:"js-array-q3",question:"What is the purpose of the second argument in reduce(callback, initialValue)?",options:["It defines the number of elements to process","It sets the starting value of the accumulator","It is a backup callback function","It specifies the final returning array type"],correctIndex:1,explanation:"The second argument to reduce() defines the initialValue of the accumulator on the first iteration. If omitted, the first element of the array is used."}]},{id:"js-async",title:"Chapter 3: Asynchronous Flow (Promises & Async/Await)",content:"JavaScript execution is single-threaded. Asynchronous actions are managed via the microtask event queue. Modern JS leverages Promises and the async/await syntax to write asynchronous queries that look synchronous.",codeSnippet:{code:`// Promise Fetch
function fetchUser(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => resolve({ id, name: "Alice" }), 1000);
  });
}

// Async/Await consumer
async function run() {
  try {
    console.log("Loading...");
    const user = await fetchUser(101);
    console.log("User Loaded:", user.name);
  } catch (error) {
    console.error("Failed:", error);
  }
}`,language:"javascript"},summary:"An async function always returns a Promise. The await keyword pauses function execution block until the promise settles, without freezing the main browser thread.",subtopicChecklist:["Understanding Javascript call stack and single-threaded execution","Understanding Promise status lifecycle (Pending, Fulfilled, Rejected)","Writing async functions using the await keyword","Implementing proper asynchronous error handling using try-catch blocks"],quizQuestions:[{id:"js-async-q1",question:"What type of value does an async function always return?",options:["A Promise object","The resolved data directly","A callback function reference","undefined by default"],correctIndex:0,explanation:"Any function declared with the async keyword automatically wraps its return value in a resolved Promise."},{id:"js-async-q2",question:"What is the benefit of the await keyword in an async function?",options:["It accelerates the execution speed of API calls","It makes asynchronous code look and behave like synchronous code","It prevents any errors from throwing","It runs multiple promises in parallel"],correctIndex:1,explanation:"await pauses execution inside the async function block until the promise settles, making asynchronous loops and code sequences highly readable like standard synchronous code."},{id:"js-async-q3",question:"How do you catch errors when using async/await syntax?",options:["By attaching a .catch() callback at the end of the async function","By wrapping the awaited code block inside try { ... } catch (err) { ... }","Errors are ignored automatically","By using a conditional if-else check"],correctIndex:1,explanation:"A try-catch block is the standard and recommended way to capture errors or rejected promises inside async/await code structures."}]}]}};